module comparator_32bit (
    input [31:0] cmp_A,
    input [31:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);
    always @(*) begin
        if (cmp_A > B) begin
            A_greater = 1;
            A_equal = 0;
            A_less = 0;
        end else if (cmp_A == B) begin
            A_greater = 0;
            A_equal = 1;
            A_less = 0;
        end else begin
            A_greater = 0;
            A_equal = 0;
            A_less = 1;
        end
    end
endmodule
